import pandas as pd
import numpy as np
import os

def ensure_input_data():
    if not os.path.exists('campaign_data.csv'):
        data = {
            'Campaign': ['#1', '#2', '#3', '#4', '#5'],
            'Marketing expenditure': [300000, 200000, 400000, 300000, 100000],
            'Units sold': [60000, 50000, 90000, 80000, 30000]
        }
        df = pd.DataFrame(data)
        df.to_csv('campaign_data.csv', index=False)

def desired_marketing_expenditure(desired_units_sold=60000):
    ensure_input_data()

    df = pd.read_csv('campaign_data.csv')
    df_clean = df.dropna(subset=['Marketing expenditure', 'Units sold'])
    df_clean.to_csv('cleaned_campaign_data.csv', index=False)

    X = df_clean['Marketing expenditure'].values
    y = df_clean['Units sold'].values

    m, c = np.polyfit(X, y, 1)

    params = pd.DataFrame({
        'parameter': ['slope', 'intercept'],
        'value': [m, c]
    })
    params.to_csv('model_parameters.csv', index=False)

    if m == 0:
        required_expenditure = 0.0
    else:
        required_expenditure = (desired_units_sold - c) / m

    with open('required_expenditure.txt', 'w') as f:
        f.write(str(float(required_expenditure)))

    return float(required_expenditure)

if __name__ == "__main__":
    result = desired_marketing_expenditure(60000)

